&lt;p&gt;&lt;span style=&quot;&quot;&gt;Let the quantity of each sample&amp;nbsp;be 100 ml&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;According to the question,&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;1st sample contain = 80ml water + 20ml milk&lt;/p&gt;

&lt;p&gt;2nd sample contain = 20ml water + 80ml milk&lt;/p&gt;

&lt;p&gt;Mixing both the samples = (&lt;span style=&quot;&quot;&gt;80ml water + 20ml milk&lt;/span&gt;) + (&lt;span style=&quot;&quot;&gt;20ml water + 80ml milk&lt;/span&gt;)&lt;/p&gt;

&lt;p&gt;&amp;rArr; Mixture =&amp;nbsp;(80ml water + 20ml water) + (20ml milk&amp;nbsp;+ 80ml milk)&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;rArr;&amp;nbsp;Mixture =&amp;nbsp;(100ml water&lt;/span&gt;&lt;span style=&quot;&quot;&gt;) + (10&lt;/span&gt;&lt;span style=&quot;&quot;&gt;0ml milk)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;Total quantity of mixture = 200ml&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Then total milk content = (100/200)&amp;nbsp;&amp;times; 100&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;rArr;&amp;nbsp;&lt;/span&gt;Total milk = 1/2&amp;nbsp;&amp;times; 100 = 50%&lt;/p&gt;

